(15,0,'2026-07-22 13:56:04','2026-07-22 11:56:04','<!-- wp:group {\"align\":\"full\",\"className\":\"ais-hero\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"1200px\"}} -->\n<div class=\"wp-block-group alignfull ais-hero\"><!-- wp:columns {\"verticalAlignment\":\"center\",\"style\":{\"spacing\":{\"blockGap\":{\"left\":\"var:preset|spacing|lg\"}}}} -->\n<div class=\"wp-block-columns are-vertically-aligned-center\"><!-- wp:column {\"verticalAlignment\":\"center\",\"width\":\"58%\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center\" style=\"flex-basis:58%\"><!-- wp:paragraph {\"className\":\"eyebrow\",\"textColor\":\"secondary\"} -->\n<p class=\"eyebrow has-secondary-color has-text-color\">Astrologie · Schweiz · Zug</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":1,\"textColor\":\"white\",\"fontSize\":\"3xl\"} -->\n<h1 class=\"wp-block-heading has-white-color has-text-color has-3-xl-font-size\">Astrologie Schweiz – Entdecken Sie Ihr Potenzial und gestalten Sie Ihr Leben bewusst</h1>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Herzlich willkommen. Ich bin Petra Müller und begleite Menschen aus der ganzen Schweiz dabei, sich selbst besser kennenzulernen und ihr Leben bewusster zu gestalten. Mit einer persönlichen astrologischen Beratung und einem individuell erstellten Geburtshoroskop gewinnen Sie wertvolle Erkenntnisse über Ihre Persönlichkeit, Ihre Stärken und die Themen, die Sie auf Ihrem Lebensweg begleiten.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Astrologie Schweiz bedeutet für mich nicht, die Zukunft vorherzusagen, sondern Menschen dabei zu unterstützen, ihre eigenen Möglichkeiten zu erkennen, innere Klarheit zu gewinnen und ihr Potenzial Schritt für Schritt zu entfalten.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons {\"style\":{\"spacing\":{\"blockGap\":\"1rem\"}}} -->\n<div class=\"wp-block-buttons\"><!-- wp:button -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"/kontakt/\">Kostenloses Kennenlerngespräch vereinbaren</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"className\":\"is-style-outline\"} -->\n<div class=\"wp-block-button is-style-outline\"><a class=\"wp-block-button__link wp-element-button btn-ghost\" href=\"/angebot/\">Angebot entdecken</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons -->\n\n<!-- wp:group {\"className\":\"ais-hero-meta\",\"layout\":{\"type\":\"flex\",\"flexWrap\":\"wrap\"}} -->\n<div class=\"wp-block-group ais-hero-meta\"><!-- wp:group -->\n<div class=\"wp-block-group\"><!-- wp:paragraph -->\n<p><strong>15+</strong><span>Jahre Erfahrung</span></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:group -->\n<div class=\"wp-block-group\"><!-- wp:paragraph -->\n<p><strong>1\'200+</strong><span>Zufriedene Klient:innen</span></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:group -->\n<div class=\"wp-block-group\"><!-- wp:paragraph -->\n<p><strong>5.0 ★</strong><span>Google Bewertungen</span></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n\n<!-- wp:paragraph {\"fontSize\":\"xs\"} -->\n<p class=\"has-xs-font-size\"><em>Hinweis: Kennzahlen sind illustrativ für die Website-Demo.</em></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"verticalAlignment\":\"center\",\"width\":\"42%\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center hero-media\" style=\"flex-basis:42%\"><!-- wp:image {\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"http://localhost:8082/petra-mueller/wp-content/themes/ai-starter/assets/images/Bild0002_DSF_5715.jpg\" alt=\"Petra Müller – Astrologin und Coach in Zug\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n<!-- wp:group {\"align\":\"full\",\"className\":\"ais-section\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"1200px\"}} -->\n<div class=\"wp-block-group alignfull ais-section\"><!-- wp:group {\"layout\":{\"type\":\"constrained\",\"contentSize\":\"760px\"}} -->\n<div class=\"wp-block-group\"><!-- wp:paragraph {\"align\":\"center\",\"className\":\"eyebrow\"} -->\n<p class=\"has-text-align-center eyebrow\">Angebot</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"textAlign\":\"center\"} -->\n<h2 class=\"wp-block-heading has-text-align-center\">Was Ihnen die Astrologie über Ihr Leben verraten kann</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\"} -->\n<p class=\"has-text-align-center\">Jeder Mensch ist einzigartig. Genau deshalb ist auch jedes Geburtshoroskop einzigartig. Gemeinsam betrachten wir Ihre astrologische Konstellation und übersetzen diese in konkrete Impulse für Ihren Alltag.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:columns {\"style\":{\"spacing\":{\"blockGap\":{\"left\":\"1.5rem\"},\"margin\":{\"top\":\"3rem\"}}}} -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"className\":\"ais-card\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group ais-card\"><!-- wp:paragraph {\"className\":\"ais-icon\"} -->\n<p class=\"ais-icon\">☽</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Persönlichkeitsentwicklung</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Entdecken Sie Ihre Stärken, lösen Sie innere Blockaden und entfalten Sie Ihr persönliches Potenzial – Schritt für Schritt.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><a class=\"card-link\" href=\"/angebot/\">Mehr erfahren</a></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"className\":\"ais-card\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group ais-card\"><!-- wp:paragraph {\"className\":\"ais-icon\"} -->\n<p class=\"ais-icon\">◎</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Astrologische Beratung</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Ein persönliches Geburtshoroskop als Kompass für Klarheit in Beruf, Beziehung und Lebensentscheidungen.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><a class=\"card-link\" href=\"/angebot/\">Mehr erfahren</a></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"className\":\"ais-card\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group ais-card\"><!-- wp:paragraph {\"className\":\"ais-icon\"} -->\n<p class=\"ais-icon\">✦</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Vorträge &amp; Impulse</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Inspirierende Vorträge rund um Astrologie, Persönlichkeitsentwicklung und Burnout-Prävention.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><a class=\"card-link\" href=\"/vortraege/\">Mehr erfahren</a></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n<!-- wp:group {\"align\":\"full\",\"className\":\"ais-section ais-section-alt\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"1200px\"}} -->\n<div class=\"wp-block-group alignfull ais-section ais-section-alt\"><!-- wp:columns {\"verticalAlignment\":\"center\",\"style\":{\"spacing\":{\"blockGap\":{\"left\":\"var:preset|spacing|lg\"}}}} -->\n<div class=\"wp-block-columns are-vertically-aligned-center\"><!-- wp:column {\"verticalAlignment\":\"center\",\"width\":\"46%\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center\" style=\"flex-basis:46%\"><!-- wp:image {\"sizeSlug\":\"large\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"http://localhost:8082/petra-mueller/wp-content/themes/ai-starter/assets/images/Bild0036_DSF_5767.jpg\" alt=\"Beratungsraum von Petra Müller in Zug\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"verticalAlignment\":\"center\",\"width\":\"54%\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center\" style=\"flex-basis:54%\"><!-- wp:paragraph {\"className\":\"eyebrow\"} -->\n<p class=\"eyebrow\">Über mich</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Petra Müller – Ihre Wegbegleiterin in Zug</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Seit über 15 Jahren begleite ich Menschen mit Astrologie und Coaching auf ihrem persönlichen Weg. Meine Beratung verbindet fundierte astrologische Kenntnisse mit einer klaren, wertschätzenden Gesprächskultur.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Ob berufliche Neuorientierung, Beziehungsfragen oder der Wunsch nach mehr Selbsterkenntnis – gemeinsam finden wir Antworten, die Sie stärken.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"/ueber-mich/\">Mehr über mich</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n<!-- wp:group {\"align\":\"full\",\"className\":\"ais-section\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"1200px\"}} -->\n<div class=\"wp-block-group alignfull ais-section\"><!-- wp:paragraph {\"align\":\"center\",\"className\":\"eyebrow\"} -->\n<p class=\"has-text-align-center eyebrow\">Warum Petra</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"textAlign\":\"center\"} -->\n<h2 class=\"wp-block-heading has-text-align-center\">Warum sich Menschen für Petra Müller entscheiden</h2>\n<!-- /wp:heading -->\n\n<!-- wp:columns {\"style\":{\"spacing\":{\"margin\":{\"top\":\"2.5rem\"},\"blockGap\":{\"left\":\"1.25rem\"}}}} -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"className\":\"ais-card\"} -->\n<div class=\"wp-block-group ais-card\"><!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Persönliche Begleitung</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Sie stehen als Mensch im Mittelpunkt – nicht Ihr Sternzeichen.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"className\":\"ais-card\"} -->\n<div class=\"wp-block-group ais-card\"><!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Lebenserfahrung</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Erfahrungen aus dem Gesundheitswesen, als Mutter und Astrologin fliessen in jede Beratung ein.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"className\":\"ais-card\"} -->\n<div class=\"wp-block-group ais-card\"><!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Verständlich erklärt</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Komplexe Zusammenhänge werden praxisnah und nachvollziehbar vermittelt.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"className\":\"ais-card\"} -->\n<div class=\"wp-block-group ais-card\"><!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Klarheit statt Vorhersagen</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Ziel ist Selbstverständnis und bewusste Entscheidungen – keine Zukunftsprognosen.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n<!-- wp:group {\"align\":\"full\",\"className\":\"ais-section ais-section-alt\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"1200px\"}} -->\n<div class=\"wp-block-group alignfull ais-section ais-section-alt\"><!-- wp:paragraph {\"align\":\"center\",\"className\":\"eyebrow\"} -->\n<p class=\"has-text-align-center eyebrow\">Ablauf</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"textAlign\":\"center\"} -->\n<h2 class=\"wp-block-heading has-text-align-center\">So läuft Ihre Beratung ab</h2>\n<!-- /wp:heading -->\n\n<!-- wp:columns {\"style\":{\"spacing\":{\"margin\":{\"top\":\"2.5rem\"}}}} -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"className\":\"ais-card\"} -->\n<div class=\"wp-block-group ais-card\"><!-- wp:paragraph {\"className\":\"ais-icon\"} -->\n<p class=\"ais-icon\">1</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Kennenlernen</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>In einem kostenlosen Erstgespräch klären wir Ihr Anliegen und ob die Begleitung zu Ihnen passt.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"className\":\"ais-card\"} -->\n<div class=\"wp-block-group ais-card\"><!-- wp:paragraph {\"className\":\"ais-icon\"} -->\n<p class=\"ais-icon\">2</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Horoskop &amp; Vorbereitung</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Mit Geburtsdatum, -zeit und -ort erstelle ich Ihr individuelles Geburtshoroskop.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"className\":\"ais-card\"} -->\n<div class=\"wp-block-group ais-card\"><!-- wp:paragraph {\"className\":\"ais-icon\"} -->\n<p class=\"ais-icon\">3</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Gespräch &amp; Impulse</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>In der Sitzung übersetzen wir die Erkenntnisse in konkrete nächste Schritte für Ihren Alltag.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n<!-- wp:group {\"align\":\"full\",\"className\":\"ais-section\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"1200px\"}} -->\n<div class=\"wp-block-group alignfull ais-section\"><!-- wp:paragraph {\"align\":\"center\",\"fontSize\":\"xs\"} -->\n<p class=\"has-text-align-center has-xs-font-size\"><em>Illustrative Kennzahlen für die Website-Demo</em></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:group {\"className\":\"ais-stats\"} -->\n<div class=\"wp-block-group ais-stats\"><!-- wp:group {\"className\":\"ais-stat\"} -->\n<div class=\"wp-block-group ais-stat\"><!-- wp:paragraph -->\n<p><strong>15+</strong><br>Jahre Praxis</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"className\":\"ais-stat\"} -->\n<div class=\"wp-block-group ais-stat\"><!-- wp:paragraph -->\n<p><strong>1\'200+</strong><br>Klient:innen</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"className\":\"ais-stat\"} -->\n<div class=\"wp-block-group ais-stat\"><!-- wp:paragraph -->\n<p><strong>90 Min.</strong><br>Standardberatung</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"className\":\"ais-stat\"} -->\n<div class=\"wp-block-group ais-stat\"><!-- wp:paragraph -->\n<p><strong>CH-weit</strong><br>auch online</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n<!-- wp:group {\"align\":\"full\",\"className\":\"ais-section ais-section-alt\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"1200px\"}} -->\n<div class=\"wp-block-group alignfull ais-section ais-section-alt\"><!-- wp:paragraph {\"align\":\"center\",\"className\":\"eyebrow\"} -->\n<p class=\"has-text-align-center eyebrow\">Stimmen</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"textAlign\":\"center\"} -->\n<h2 class=\"wp-block-heading has-text-align-center\">Was Klient:innen sagen</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"fontSize\":\"xs\"} -->\n<p class=\"has-text-align-center has-xs-font-size\"><em>Hinweis: Die folgenden Testimonials sind Beispieltexte für die Demo-Website.</em></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:columns {\"style\":{\"spacing\":{\"margin\":{\"top\":\"2rem\"}}}} -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:quote {\"className\":\"ais-quote\"} -->\n<blockquote class=\"wp-block-quote ais-quote\"><!-- wp:paragraph -->\n<p>Die Beratung hat mir geholfen, berufliche Entscheidungen mit mehr Ruhe und Klarheit zu treffen. Ich habe mich endlich verstanden gefühlt.</p>\n<!-- /wp:paragraph --><cite>Anna R., Zürich — Beispiel-Testimonial</cite></blockquote>\n<!-- /wp:quote --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:quote {\"className\":\"ais-quote\"} -->\n<blockquote class=\"wp-block-quote ais-quote\"><!-- wp:paragraph -->\n<p>Petra erklärt Astrologie so verständlich, dass ich konkrete Impulse für meinen Alltag mitnehmen konnte – ohne esoterischen Ballast.</p>\n<!-- /wp:paragraph --><cite>Marco L., Luzern — Beispiel-Testimonial</cite></blockquote>\n<!-- /wp:quote --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:quote {\"className\":\"ais-quote\"} -->\n<blockquote class=\"wp-block-quote ais-quote\"><!-- wp:paragraph -->\n<p>Das Kennenlerngespräch war wertschätzend und klar. Die Sitzung danach hat mir neue Perspektiven auf meine Stärken gegeben.</p>\n<!-- /wp:paragraph --><cite>Sandra K., Zug — Beispiel-Testimonial</cite></blockquote>\n<!-- /wp:quote --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n<!-- wp:group {\"align\":\"full\",\"className\":\"ais-section ais-faq\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"800px\"}} -->\n<div class=\"wp-block-group alignfull ais-section ais-faq\"><!-- wp:paragraph {\"align\":\"center\",\"className\":\"eyebrow\"} -->\n<p class=\"has-text-align-center eyebrow\">FAQ</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"textAlign\":\"center\"} -->\n<h2 class=\"wp-block-heading has-text-align-center\">Häufig gestellte Fragen</h2>\n<!-- /wp:heading -->\n\n<!-- wp:details {\"open\":true} -->\n<details class=\"wp-block-details\" open><summary>Was brauche ich für eine astrologische Beratung?</summary><!-- wp:paragraph -->\n<p>Für Ihr Geburtshoroskop benötige ich Geburtsdatum, möglichst genaue Geburtszeit und Geburtsort. Je präziser die Zeit, desto differenzierter die Deutung.</p>\n<!-- /wp:paragraph --></details>\n<!-- /wp:details -->\n\n<!-- wp:details -->\n<details class=\"wp-block-details\"><summary>Finden Beratungen nur vor Ort in Zug statt?</summary><!-- wp:paragraph -->\n<p>Nein. Sie können mich in der Praxis in Zug besuchen oder eine Videoberatung wählen – schweizweit und auch aus dem Ausland.</p>\n<!-- /wp:paragraph --></details>\n<!-- /wp:details -->\n\n<!-- wp:details -->\n<details class=\"wp-block-details\"><summary>Sagt Astrologie die Zukunft voraus?</summary><!-- wp:paragraph -->\n<p>Nein. Meine Arbeit zielt auf Selbsterkenntnis, Orientierung und bewusste Entscheidungen – nicht auf Vorhersagen.</p>\n<!-- /wp:paragraph --></details>\n<!-- /wp:details -->\n\n<!-- wp:details -->\n<details class=\"wp-block-details\"><summary>Wie lange dauert eine Sitzung?</summary><!-- wp:paragraph -->\n<p>Standardberatungen dauern in der Regel 75–120 Minuten, je nach gewähltem Angebot. Das Kennenlerngespräch ist kürzer und unverbindlich.</p>\n<!-- /wp:paragraph --></details>\n<!-- /wp:details -->\n\n<!-- wp:details -->\n<details class=\"wp-block-details\"><summary>Für wen eignet sich die Beratung?</summary><!-- wp:paragraph -->\n<p>Für Menschen, die Orientierung in Beruf, Beziehung, Persönlichkeitsentwicklung oder Lebensübergängen suchen und bereit sind, ehrlich hinzuschauen.</p>\n<!-- /wp:paragraph --></details>\n<!-- /wp:details --></div>\n<!-- /wp:group -->\n<!-- wp:group {\"align\":\"full\",\"className\":\"ais-cta\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"760px\"}} -->\n<div class=\"wp-block-group alignfull ais-cta\"><!-- wp:heading {\"textAlign\":\"center\",\"textColor\":\"white\"} -->\n<h2 class=\"wp-block-heading has-text-align-center has-white-color has-text-color\">Bereit für mehr Klarheit?</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\"} -->\n<p class=\"has-text-align-center\">Vereinbaren Sie ein kostenloses Kennenlerngespräch und finden Sie heraus, ob eine astrologische Beratung der richtige nächste Schritt für Sie ist.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"}} -->\n<div class=\"wp-block-buttons\"><!-- wp:button -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"/buchen/\">Termin buchen</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"className\":\"is-style-outline\"} -->\n<div class=\"wp-block-button is-style-outline\"><a class=\"wp-block-button__link wp-element-button btn-ghost\" href=\"/kontakt/\">Kontakt aufnehmen</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group -->','Home','','publish','closed','closed','','home','','','2026-07-22 13:57:02','2026-07-22 11:57:02','',0,'http://localhost:8082/petra-mueller/home/',0,'page','',0),
(16,0,'2026-07-22 13:56:05','2026-07-22 11:56:05','<!-- wp:group {\"align\":\"full\",\"className\":\"ais-page-hero\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"900px\"}} -->\n<div class=\"wp-block-group alignfull ais-page-hero\"><!-- wp:paragraph {\"className\":\"breadcrumb\"} -->\n<p class=\"breadcrumb\"><a href=\"/\">Home</a> / Angebot</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading {\"level\":1} -->\n<h1 class=\"wp-block-heading\">Persönlichkeitsentwicklung – Entfalten Sie Ihr volles Potenzial</h1>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p>Jeder Mensch trägt einzigartige Stärken, Talente und Möglichkeiten in sich. Eine astrologische Beratung verbindet Persönlichkeitsentwicklung mit den Erkenntnissen Ihres Geburtshoroskops.</p>\n<!-- /wp:paragraph -->\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"/buchen/\">Kostenloses Kennenlerngespräch vereinbaren</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group -->\n<!-- wp:group {\"align\":\"full\",\"className\":\"ais-section\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"1200px\"}} -->\n<div class=\"wp-block-group alignfull ais-section\"><!-- wp:paragraph {\"align\":\"center\",\"className\":\"eyebrow\"} -->\n<p class=\"has-text-align-center eyebrow\">Preise</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"textAlign\":\"center\"} -->\n<h2 class=\"wp-block-heading has-text-align-center\">Transparente Orientierungspreise</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\"} -->\n<p class=\"has-text-align-center\">Preise dienen der Orientierung und können je nach Anliegen angepasst werden.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:columns {\"style\":{\"spacing\":{\"margin\":{\"top\":\"2.5rem\"}}}} -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"className\":\"ais-card\"} -->\n<div class=\"wp-block-group ais-card\"><!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Klarheit für Entscheidungen</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Neue Perspektiven für private oder berufliche Herausforderungen.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"className\":\"price\"} -->\n<p class=\"price\">CHF 190 · 75 Min.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><a class=\"card-link\" href=\"/buchen/\">Buchen</a></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"className\":\"ais-card\"} -->\n<div class=\"wp-block-group ais-card\"><!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Mehr Selbstverständnis</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Persönlichkeit, Stärken und Entwicklungsmöglichkeiten vertiefen.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"className\":\"price\"} -->\n<p class=\"price\">CHF 220 · 90 Min.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><a class=\"card-link\" href=\"/buchen/\">Buchen</a></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"className\":\"ais-card\"} -->\n<div class=\"wp-block-group ais-card\"><!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Persönliche Begleitung</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Intensives Gespräch mit ausführlicher Vorbereitung und Vertiefung.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"className\":\"price\"} -->\n<p class=\"price\">CHF 280 · 120 Min.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><a class=\"card-link\" href=\"/buchen/\">Buchen</a></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n<!-- wp:group {\"align\":\"full\",\"className\":\"ais-section\",\"layout\":