(18,0,'2026-07-22 13:56:06','2026-07-22 11:56:06','<!-- wp:group {\"align\":\"full\",\"className\":\"ais-page-hero\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"900px\"}} -->\n<div class=\"wp-block-group alignfull ais-page-hero\"><!-- wp:paragraph {\"className\":\"breadcrumb\"} -->\n<p class=\"breadcrumb\"><a href=\"/\">Home</a> / Vorträge</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":1} -->\n<h1 class=\"wp-block-heading\">Vorträge zu Astrologie &amp; Persönlichkeitsentwicklung</h1>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Inspirierende Keynotes und Impulse für Unternehmen, Vereine und Organisationen – verständlich, praxisnah und ohne esoterischen Ballast.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"align\":\"full\",\"className\":\"ais-section\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"1200px\"}} -->\n<div class=\"wp-block-group alignfull ais-section\"><!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"className\":\"ais-card\"} -->\n<div class=\"wp-block-group ais-card\"><!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Astrologie verständlich</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Wie Horoskope Orientierung geben – und warum es nicht um Vorhersagen geht.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"className\":\"ais-card\"} -->\n<div class=\"wp-block-group ais-card\"><!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Burnout-Prävention</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Persönliche Muster erkennen, Ressourcen stärken und frühzeitig gegensteuern.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"className\":\"ais-card\"} -->\n<div class=\"wp-block-group ais-card\"><!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Persönlichkeitsentfaltung</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Impulse für Teams und Events, die Menschen ermutigen, Potenziale zu nutzen.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n','Vorträge','','publish','closed','closed','','vortraege','','','2026-07-22 13:56:06','2026-07-22 11:56:06','',0,'http://localhost:8082/petra-mueller/vortraege/',0,'page','',0),
(19,0,'2026-07-22 13:56:06','2026-07-22 11:56:06','<!-- wp:group {\"align\":\"full\",\"className\":\"ais-page-hero\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"900px\"}} -->\n<div class=\"wp-block-group alignfull ais-page-hero\"><!-- wp:paragraph {\"className\":\"breadcrumb\"} -->\n<p class=\"breadcrumb\"><a href=\"/\">Home</a> / Über mich</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading {\"level\":1} -->\n<h1 class=\"wp-block-heading\">Petra Müller – Astrologin in Zug</h1>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p>Ich bin dreifache Mutter, habe lange im Gesundheitswesen gearbeitet und begleite heute Menschen mit Astrologie auf ihrem persönlichen Lebensweg.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n<!-- wp:group {\"align\":\"full\",\"className\":\"ais-section ais-section-alt\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"1200px\"}} -->\n<div class=\"wp-block-group alignfull ais-section ais-section-alt\"><!-- wp:columns {\"verticalAlignment\":\"center\",\"style\":{\"spacing\":{\"blockGap\":{\"left\":\"var:preset|spacing|lg\"}}}} -->\n<div class=\"wp-block-columns are-vertically-aligned-center\"><!-- wp:column {\"verticalAlignment\":\"center\",\"width\":\"46%\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center\" style=\"flex-basis:46%\"><!-- wp:image {\"sizeSlug\":\"large\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"http://localhost:8082/petra-mueller/wp-content/themes/ai-starter/assets/images/Bild0036_DSF_5767.jpg\" alt=\"Beratungsraum von Petra Müller in Zug\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"verticalAlignment\":\"center\",\"width\":\"54%\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center\" style=\"flex-basis:54%\"><!-- wp:paragraph {\"className\":\"eyebrow\"} -->\n<p class=\"eyebrow\">Über mich</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Petra Müller – Ihre Wegbegleiterin in Zug</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Seit über 15 Jahren begleite ich Menschen mit Astrologie und Coaching auf ihrem persönlichen Weg. Meine Beratung verbindet fundierte astrologische Kenntnisse mit einer klaren, wertschätzenden Gesprächskultur.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Ob berufliche Neuorientierung, Beziehungsfragen oder der Wunsch nach mehr Selbsterkenntnis – gemeinsam finden wir Antworten, die Sie stärken.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"/ueber-mich/\">Mehr über mich</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n<!-- wp:group {\"align\":\"full\",\"className\":\"ais-section\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"760px\"}} -->\n<div class=\"wp-block-group alignfull ais-section\"><!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Mission, Vision &amp; Werte</h2>\n<!-- /wp:heading -->\n<!-- wp:heading {\"level\":3} --><h3 class=\"wp-block-heading\">Mission</h3><!-- /wp:heading -->\n<!-- wp:paragraph --><p>Menschen dabei unterstützen, sich selbst besser zu verstehen und ihr Leben bewusst zu gestalten – mit Klarheit, Empathie und fundierter Astrologie.</p><!-- /wp:paragraph -->\n<!-- wp:heading {\"level\":3} --><h3 class=\"wp-block-heading\">Vision</h3><!-- /wp:heading -->\n<!-- wp:paragraph --><p>Eine Schweiz, in der Selbsterkenntnis zugänglich ist – ohne Vorhersagen, mit Verantwortung.</p><!-- /wp:paragraph -->\n<!-- wp:heading {\"level\":3} --><h3 class=\"wp-block-heading\">Werte</h3><!-- /wp:heading -->\n<!-- wp:list --><ul class=\"wp-block-list\"><!-- wp:list-item --><li>Wertschätzung und Augenhöhe</li><!-- /wp:list-item --><!-- wp:list-item --><li>Verständlichkeit statt Fachjargon</li><!-- /wp:list-item --><!-- wp:list-item --><li>Diskretion und Vertrauen</li><!-- /wp:list-item --><!-- wp:list-item --><li>Praxisnahe Impulse</li><!-- /wp:list-item --></ul><!-- /wp:list --></div>\n<!-- /wp:group -->','Über mich','','publish','closed','closed','','ueber-mich','','','2026-07-22 13:58:01','2026-07-22 11:58:01','',0,'http://localhost:8082/petra-mueller/ueber-mich/',0,'page','',0),
(20,0,'2026-07-22 13:56:07','2026-07-22 11:56:07','<!-- wp:group {\"align\":\"full\",\"className\":\"ais-page-hero\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"900px\"}} -->\n<div class=\"wp-block-group alignfull ais-page-hero\"><!-- wp:paragraph {\"className\":\"breadcrumb\"} -->\n<p class=\"breadcrumb\"><a href=\"/\">Home</a> / Kontakt</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading {\"level\":1} -->\n<h1 class=\"wp-block-heading\">Astrologin Schweiz – Ich freue mich auf Ihre Kontaktaufnahme</h1>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p>Sie möchten mehr über meine Beratungen erfahren oder einen Termin vereinbaren? Dann freue ich mich, Sie kennenzulernen.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n<!-- wp:group {\"align\":\"full\",\"className\":\"ais-section\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"1200px\"}} -->\n<div class=\"wp-block-group alignfull ais-section\"><!-- wp:heading {\"textAlign\":\"center\"} -->\n<h2 class=\"wp-block-heading has-text-align-center\">Nehmen Sie unverbindlich Kontakt auf</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\"} -->\n<p class=\"has-text-align-center\">Manchmal genügt bereits ein erstes Gespräch, um herauszufinden, ob eine Beratung der richtige Schritt ist.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:columns {\"style\":{\"spacing\":{\"margin\":{\"top\":\"2.5rem\"}}}} -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"className\":\"ais-card\"} -->\n<div class=\"wp-block-group ais-card\"><!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Praxis Zug</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Persönliche Beratung vor Ort in ruhiger Atmosphäre.<br>Adresse: Musterstrasse 12, 6300 Zug (Platzhalter)</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"className\":\"ais-card\"} -->\n<div class=\"wp-block-group ais-card\"><!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Telefon &amp; E-Mail</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"tel:+41410000000\">+41 41 000 00 00</a><br><a href=\"mailto:kontakt@example.com\">kontakt@example.com</a></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"className\":\"ais-card\"} -->\n<div class=\"wp-block-group ais-card\"><!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Online</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Videoberatung für Klient:innen aus der ganzen Schweiz und darüber hinaus.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"2rem\"}}}} -->\n<p class=\"has-text-align-center\">Nutzen Sie das <a href=\"/buchen/\">Buchungsformular</a> oder schreiben Sie mir direkt eine Nachricht. (Kontaktformular-Platzhalter – in Produktion an ein Formular-Plugin oder nativen Block anbinden.)</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n<!-- wp:group {\"align\":\"full\",\"className\":\"ais-cta\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"760px\"}} -->\n<div class=\"wp-block-group alignfull ais-cta\"><!-- wp:heading {\"textAlign\":\"center\",\"textColor\":\"white\"} -->\n<h2 class=\"wp-block-heading has-text-align-center has-white-color has-text-color\">Bereit für mehr Klarheit?</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\"} -->\n<p class=\"has-text-align-center\">Vereinbaren Sie ein kostenloses Kennenlerngespräch und finden Sie heraus, ob eine astrologische Beratung der richtige nächste Schritt für Sie ist.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"}} -->\n<div class=\"wp-block-buttons\"><!-- wp:button -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"/buchen/\">Termin buchen</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"className\":\"is-style-outline\"} -->\n<div class=\"wp-block-button is-style-outline\"><a class=\"wp-block-button__link wp-element-button btn-ghost\" href=\"/kontakt/\">Kontakt aufnehmen</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group -->','Kontakt','','publish','closed','closed','','kontakt','','','2026-07-22 13:57:39','2026-07-22 11:57:39','',0,'http://localhost:8082/petra-mueller/kontakt/',0,'page','',0),
(21,0,'2026-07-22 13:56:07','2026-07-22 11:56:07','<!-- wp:group {\"align\":\"full\",\"className\":\"ais-page-hero\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"900px\"}} -->\n<div class=\"wp-block-group alignfull ais-page-hero\"><!-- wp:paragraph {\"className\":\"breadcrumb\"} -->\n<p class=\"breadcrumb\"><a href=\"/\">Home</a> / Buchen</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":1} -->\n<h1 class=\"wp-block-heading\">Termin buchen</h1>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Wählen Sie Ihr Anliegen und vereinbaren Sie ein kostenloses Kennenlerngespräch oder eine Beratung. (Platzhalter: In Produktion Buchungskalender oder Formular anbinden.)</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Kennenlerngespräch (kostenlos)</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Astrologische Beratung 75–120 Min.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Vortragsanfrage für Events</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>E-Mail: <a href=\"mailto:kontakt@example.com\">kontakt@example.com</a> · Telefon: <a href=\"tel:+41410000000\">+41 41 000 00 00</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"/kontakt/\">Stattdessen Kontaktseite öffnen</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group -->','Termin buchen','','publish','closed','closed','','buchen','','','2026-07-22 13:56:07','2026-07-22 11:56:07','',0,'http://localhost:8082/petra-mueller/buchen/',0,'page','',0),
(22,0,'2026-07-22 13:56:07','2026-07-22 11:56:07','<!-- wp:group {\"align\":\"full\",\"className\":\"ais-page-hero\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"900px\"}} -->\n<div class=\"wp-block-group alignfull ais-page-hero\"><!-- wp:paragraph {\"className\":\"breadcrumb\"} -->\n<p class=\"breadcrumb\"><a href=\"/\">Home</a> / Feedbacks</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading {\"level\":1} --><h1 class=\"wp-block-heading\">Feedbacks</h1><!-- /wp:heading -->\n<!-- wp:paragraph --><p>Erfahrungen von Menschen auf dem Weg der Selbsterkenntnis.</p><!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n<!-- wp:group {\"align\":\"full\",\"className\":\"ais-section ais-section-alt\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"1200px\"}} -->\n<div class=\"wp-block-group alignfull ais-section ais-section-alt\"><!-- wp:paragraph {\"align\":\"center\",\"className\":\"eyebrow\"} -->\n<p class=\"has-text-align-center eyebrow\">Stimmen</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"textAlign\":\"center\"} -->\n<h2 class=\"wp-block-heading has-text-align-center\">Was Klient:innen sagen</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"fontSize\":\"xs\"} -->\n<p class=\"has-text-align-center has-xs-font-size\"><em>Hinweis: Die folgenden Testimonials sind Beispieltexte für die Demo-Website.</em></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:columns {\"style\":{\"spacing\":{\"margin\":{\"top\":\"2rem\"}}}} -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:quote {\"className\":\"ais-quote\"} -->\n<blockquote class=\"wp-block-quote ais-quote\"><!-- wp:paragraph -->\n<p>Die Beratung hat mir geholfen, berufliche Entscheidungen mit mehr Ruhe und Klarheit zu treffen. Ich habe mich endlich verstanden gefühlt.</p>\n<!-- /wp:paragraph --><cite>Anna R., Zürich — Beispiel-Testimonial</cite></blockquote>\n<!-- /wp:quote --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:quote {\"className\":\"ais-quote\"} -->\n<blockquote class=\"wp-block-quote ais-quote\"><!-- wp:paragraph -->\n<p>Petra erklärt Astrologie so verständlich, dass ich konkrete Impulse für meinen Alltag mitnehmen konnte – ohne esoterischen Ballast.</p>\n<!-- /wp:paragraph --><cite>Marco L., Luzern — Beispiel-Testimonial</cite></blockquote>\n<!-- /wp:quote --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:quote {\"className\":\"ais-quote\"} -->\n<blockquote class=\"wp-block-quote ais-quote\"><!-- wp:paragraph -->\n<p>Das Kennenlerngespräch war wertschätzend und klar. Die Sitzung danach hat mir neue Perspektiven auf meine Stärken gegeben.</p>\n<!-- /wp:paragraph --><cite>Sandra K., Zug — Beispiel-Testimonial</cite></blockquote>\n<!-- /wp:quote --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n<!-- wp:group {\"align\":\"full\",\"className\":\"ais-cta\",\"layout\":{\"type\":\"constrained\",\"contentSize\":\"760px\"}} -->\n<div class=\"wp-block-group alignfull ais-cta\"><!-- wp:heading {\"textAlign\":\"center\",\"textColor\":\"white\"} -->\n<h2 class=\"wp-block-heading has-text-align-center has-white-color has-text-color\">Bereit für mehr Klarheit?</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\"} -->\n<p class=\"has-text-align-center\">Vereinbaren Sie ein kostenloses Kennenlerngespräch und finden Sie heraus, ob eine astrologische Beratung der richtige nächste Schritt für Sie ist.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"}} -->\n<div class=\"wp-block-buttons\"><!-- wp:button -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"/buchen/\">Termin buchen</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"className\":\"is-style-outline\"} -->\n<div class=\"wp-block-button is-style-outline\"><a class=\"wp-block-button__link wp-element-button btn-ghost\" href=\"/kontakt/\">Kontakt aufnehmen</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group -->','Feedbacks','','publish','closed','closed','','feedbacks','','','2026-07-22 13:57:40','2026-07-22 11:57:40','',0,'http://localhost:8082/petra-mueller/feedbacks/',0,'page','',0),
